import React, { useState, useEffect, useRef } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    positive: '#10b981',
    negative: '#f43f5e',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
  },
  font: "'JetBrains Mono', monospace",
};

const clusterColors = ['#f472b6', '#38bdf8', '#a3e635', '#fbbf24'];

const examples = [
  {
    name: '2 Clusters',
    points: [[1,2],[1,4],[1,0],[2,3],[2,1],[10,2],[10,4],[10,0],[9,3],[11,1]],
    k: 2,
    initialCentroids: [[0,0],[8,8]],
  },
  {
    name: '3 Clusters',
    points: [[1,1],[2,1],[1,2],[8,1],[9,1],[8,2],[5,8],[5,9],[6,8]],
    k: 3,
    initialCentroids: [[0,0],[10,0],[5,10]],
  },
  {
    name: '4 Corners',
    points: [[0,0],[1,0],[0,1],[1,1],[9,0],[10,0],[9,1],[10,1],[0,9],[1,9],[0,10],[1,10],[9,9],[10,9],[9,10],[10,10]],
    k: 4,
    initialCentroids: [[2,2],[8,2],[2,8],[8,8]],
  },
];

const stepInfo = [
  {
    title: 'Explore: Place Your Centroids',
    desc: 'Drag the colored squares to position the initial centroids. Try placing them near where you think cluster centers should be, or far away to see how K-Means recovers.',
    color: theme.colors.primary,
  },
  {
    title: 'Step 1: Assign Points to Nearest Centroid',
    desc: 'Each point is assigned to its closest centroid. Points are colored by their cluster. Notice how the initial centroid positions affect assignments.',
    color: theme.colors.blue,
  },
  {
    title: 'Step 2: Update Centroids',
    desc: 'Each centroid moves to the mean (average position) of all points assigned to it. Watch the centroids shift toward the center of their clusters.',
    color: theme.colors.green,
  },
  {
    title: 'Step 3: Re-assign Points',
    desc: 'With centroids in new positions, we reassign points. Some points may switch clusters as centroid positions have changed.',
    color: theme.colors.blue,
  },
  {
    title: 'Step 4: Update Centroids Again',
    desc: 'Centroids move again to the new cluster means. The movements get smaller as we approach convergence.',
    color: theme.colors.green,
  },
  {
    title: 'Converging to Final Clusters',
    desc: 'Watch K-Means iterate until centroids stop moving. The algorithm has converged when assignments no longer change.',
    color: theme.colors.primary,
  },
];

export default function App() {
  const [exampleIdx, setExampleIdx] = useState(0);
  const [step, setStep] = useState(0);
  const [playing, setPlaying] = useState(false);
  const [iteration, setIteration] = useState(0);
  const [centroids, setCentroids] = useState(() => examples[0].initialCentroids.map(c => [...c]));
  const [assignments, setAssignments] = useState([]);
  const [prevCentroids, setPrevCentroids] = useState([]);
  const [iterating, setIterating] = useState(false);
  const [dragging, setDragging] = useState(null);
  const [converged, setConverged] = useState(false);
  const canvasRef = useRef(null);
  const iterRef = useRef(null);

  const totalSteps = 5;
  const ex = examples[exampleIdx];
  const size = 320;
  const padding = 30;
  const plotSize = size - 2 * padding;

  // Full reset function
  const fullReset = (idx) => {
    const newEx = examples[idx];
    if (iterRef.current) {
      clearInterval(iterRef.current);
      iterRef.current = null;
    }
    setCentroids(newEx.initialCentroids.map(c => [...c]));
    setAssignments([]);
    setPrevCentroids([]);
    setStep(0);
    setPlaying(false);
    setIteration(0);
    setIterating(false);
    setConverged(false);
    setDragging(null);
  };

  // Handle example change
  const handleExampleChange = (idx) => {
    fullReset(idx);
    setExampleIdx(idx);
  };

  const euclidean = (a, b) => Math.sqrt((a[0]-b[0])**2 + (a[1]-b[1])**2);

  const assignPoints = (cents, points) => {
    return points.map(p => {
      let minDist = Infinity, minIdx = 0;
      cents.forEach((c, i) => {
        const d = euclidean(p, c);
        if (d < minDist) { minDist = d; minIdx = i; }
      });
      return minIdx;
    });
  };

  const updateCentroids = (assigns, cents, points) => {
    const newCents = cents.map((c, i) => {
      const clusterPts = points.filter((_, pi) => assigns[pi] === i);
      if (clusterPts.length === 0) return [...c];
      const meanX = clusterPts.reduce((s, p) => s + p[0], 0) / clusterPts.length;
      const meanY = clusterPts.reduce((s, p) => s + p[1], 0) / clusterPts.length;
      return [Math.round(meanX * 10000) / 10000, Math.round(meanY * 10000) / 10000];
    });
    return newCents;
  };

  const centroidsEqual = (a, b) => {
    if (a.length !== b.length) return false;
    return a.every((c, i) => Math.abs(c[0] - b[i][0]) < 0.0001 && Math.abs(c[1] - b[i][1]) < 0.0001);
  };

  const reset = () => fullReset(exampleIdx);

  const next = () => {
    if (step >= totalSteps) return;
    const nextStep = step + 1;
    setStep(nextStep);

    if (nextStep === 1) {
      setAssignments(assignPoints(centroids, ex.points));
    } else if (nextStep === 2) {
      setPrevCentroids(centroids.map(c => [...c]));
      const newCents = updateCentroids(assignments, centroids, ex.points);
      setCentroids(newCents);
      setIteration(1);
    } else if (nextStep === 3) {
      setAssignments(assignPoints(centroids, ex.points));
    } else if (nextStep === 4) {
      setPrevCentroids(centroids.map(c => [...c]));
      const newCents = updateCentroids(assignments, centroids, ex.points);
      setCentroids(newCents);
      setIteration(2);
    } else if (nextStep === 5) {
      setIterating(true);
    }
  };

  const prev = () => step > 0 && setStep(step - 1);

  const auto = async () => {
    setPlaying(true);
    let curCents = centroids.map(c => [...c]);
    let curAssigns = [...assignments];
    let curIter = iteration;

    for (let s = step; s <= totalSteps; s++) {
      setStep(s);
      if (s === 1) {
        curAssigns = assignPoints(curCents, ex.points);
        setAssignments(curAssigns);
      } else if (s === 2) {
        setPrevCentroids(curCents.map(c => [...c]));
        curCents = updateCentroids(curAssigns, curCents, ex.points);
        setCentroids(curCents);
        curIter = 1;
        setIteration(1);
      } else if (s === 3) {
        curAssigns = assignPoints(curCents, ex.points);
        setAssignments(curAssigns);
      } else if (s === 4) {
        setPrevCentroids(curCents.map(c => [...c]));
        curCents = updateCentroids(curAssigns, curCents, ex.points);
        setCentroids(curCents);
        curIter = 2;
        setIteration(2);
      } else if (s === 5) {
        setIterating(true);
      }
      await new Promise(r => setTimeout(r, 800));
    }
    setPlaying(false);
  };

  // Auto iteration loop
  useEffect(() => {
    if (!iterating || converged || iteration >= 20) {
      if (iterRef.current) {
        clearInterval(iterRef.current);
        iterRef.current = null;
      }
      return;
    }

    iterRef.current = setInterval(() => {
      setCentroids(prevCents => {
        const assigns = assignPoints(prevCents, ex.points);
        setAssignments(assigns);
        const newCents = updateCentroids(assigns, prevCents, ex.points);

        if (centroidsEqual(prevCents, newCents)) {
          setConverged(true);
          if (iterRef.current) {
            clearInterval(iterRef.current);
            iterRef.current = null;
          }
          return prevCents;
        }

        setPrevCentroids(prevCents.map(c => [...c]));
        setIteration(prev => prev + 1);
        return newCents;
      });
    }, 400);

    return () => { 
      if (iterRef.current) {
        clearInterval(iterRef.current);
        iterRef.current = null;
      }
    };
  }, [iterating, converged, exampleIdx, ex.points]);

  // Mouse handlers for dragging centroids
  const getMousePos = (e) => {
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const bounds = { min: 0, max: 12 };
    const px = bounds.min + ((x - padding) / plotSize) * (bounds.max - bounds.min);
    const py = bounds.max - ((y - padding) / plotSize) * (bounds.max - bounds.min);

    return [
      Math.max(bounds.min, Math.min(bounds.max, px)),
      Math.max(bounds.min, Math.min(bounds.max, py)),
    ];
  };

  const handleMouseDown = (e) => {
    if (step > 0) return;
    const pos = getMousePos(e);

    let closest = null;
    let minDist = 1.5;
    centroids.forEach((c, i) => {
      const d = euclidean(pos, c);
      if (d < minDist) {
        minDist = d;
        closest = i;
      }
    });

    if (closest !== null) {
      setDragging(closest);
    }
  };

  const handleMouseMove = (e) => {
    if (dragging === null || step > 0) return;
    const pos = getMousePos(e);
    setCentroids(prev => {
      const newCents = [...prev];
      newCents[dragging] = pos;
      return newCents;
    });
  };

  const handleMouseUp = () => {
    setDragging(null);
  };

  // Canvas drawing
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');

    ctx.fillStyle = theme.colors.surface;
    ctx.fillRect(0, 0, size, size);

    const bounds = { min: 0, max: 12 };
    const scaleX = (x) => padding + ((x - bounds.min) / (bounds.max - bounds.min)) * plotSize;
    const scaleY = (y) => size - padding - ((y - bounds.min) / (bounds.max - bounds.min)) * plotSize;

    // Grid
    ctx.strokeStyle = theme.colors.border;
    ctx.lineWidth = 1;
    for (let i = 0; i <= 6; i++) {
      const x = padding + (i / 6) * plotSize;
      const y = padding + (i / 6) * plotSize;
      ctx.beginPath(); ctx.moveTo(x, padding); ctx.lineTo(x, size - padding); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(padding, y); ctx.lineTo(size - padding, y); ctx.stroke();
    }

    // Assignment lines (during assignment steps) - with safety check
    if ((step === 1 || step === 3 || step >= 5) && assignments.length === ex.points.length) {
      ex.points.forEach((p, i) => {
        const ci = assignments[i];
        // Safety check: make sure centroid exists
        if (ci >= 0 && ci < centroids.length && centroids[ci]) {
          ctx.strokeStyle = clusterColors[ci % clusterColors.length] + '60';
          ctx.lineWidth = 1;
          ctx.setLineDash([4, 4]);
          ctx.beginPath();
          ctx.moveTo(scaleX(p[0]), scaleY(p[1]));
          ctx.lineTo(scaleX(centroids[ci][0]), scaleY(centroids[ci][1]));
          ctx.stroke();
        }
      });
      ctx.setLineDash([]);
    }

    // Centroid movement arrows (during update steps)
    if ((step === 2 || step === 4) && prevCentroids.length === centroids.length) {
      centroids.forEach((c, i) => {
        const prev = prevCentroids[i];
        if (prev && euclidean(c, prev) > 0.01) {
          ctx.strokeStyle = clusterColors[i % clusterColors.length];
          ctx.lineWidth = 2;
          ctx.beginPath();
          ctx.moveTo(scaleX(prev[0]), scaleY(prev[1]));
          ctx.lineTo(scaleX(c[0]), scaleY(c[1]));
          ctx.stroke();

          const angle = Math.atan2(scaleY(c[1]) - scaleY(prev[1]), scaleX(c[0]) - scaleX(prev[0]));
          const ax = scaleX(c[0]);
          const ay = scaleY(c[1]);
          ctx.beginPath();
          ctx.moveTo(ax, ay);
          ctx.lineTo(ax - 8 * Math.cos(angle - 0.4), ay - 8 * Math.sin(angle - 0.4));
          ctx.lineTo(ax - 8 * Math.cos(angle + 0.4), ay - 8 * Math.sin(angle + 0.4));
          ctx.closePath();
          ctx.fillStyle = clusterColors[i % clusterColors.length];
          ctx.fill();
        }
      });
    }

    // Data points
    ex.points.forEach((p, i) => {
      let color = theme.colors.textMuted;
      if (step >= 1 && assignments.length === ex.points.length) {
        const ci = assignments[i];
        if (ci >= 0 && ci < centroids.length) {
          color = clusterColors[ci % clusterColors.length];
        }
      }
      ctx.fillStyle = color;
      ctx.beginPath();
      ctx.arc(scaleX(p[0]), scaleY(p[1]), 6, 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = theme.colors.surface;
      ctx.lineWidth = 1;
      ctx.stroke();
    });

    // Centroids (as squares)
    centroids.forEach((c, i) => {
      if (!c) return;
      const cx = scaleX(c[0]);
      const cy = scaleY(c[1]);
      const s = step === 0 ? 14 : 12;

      if (step === 0) {
        ctx.fillStyle = clusterColors[i % clusterColors.length] + '40';
        ctx.fillRect(cx - s - 4, cy - s - 4, (s + 4) * 2, (s + 4) * 2);
      }

      ctx.fillStyle = clusterColors[i % clusterColors.length];
      ctx.fillRect(cx - s, cy - s, s * 2, s * 2);
      ctx.strokeStyle = theme.colors.text;
      ctx.lineWidth = 2;
      ctx.strokeRect(cx - s, cy - s, s * 2, s * 2);

      ctx.fillStyle = theme.colors.text;
      ctx.font = 'bold 10px JetBrains Mono, monospace';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('C' + (i + 1), cx, cy);
    });

    if (step === 0) {
      ctx.fillStyle = theme.colors.textSecondary;
      ctx.font = '10px JetBrains Mono, monospace';
      ctx.textAlign = 'center';
      ctx.fillText('Drag squares to move centroids', size / 2, size - 10);
    }

  }, [step, centroids, assignments, prevCentroids, exampleIdx, iteration, dragging, ex.points]);

  const formatNum = (n) => n.toFixed(2);

  return (
    <div style={{
      background: theme.colors.background,
      padding: '16px',
      fontFamily: theme.font,
      color: theme.colors.text,
      minHeight: '100vh',
      boxSizing: 'border-box',
    }}>
      {/* Header */}
      <div style={{ textAlign: 'center', marginBottom: '12px' }}>
        <div style={{ fontSize: '18px', fontWeight: '700' }}>
          K-Means Clustering
        </div>
        <div style={{ fontSize: '11px', color: theme.colors.textSecondary }}>
          {step === 0 ? 'Position centroids, then click Start' : 'Watch points cluster around centroids'}
        </div>
      </div>

      {/* Example Tabs */}
      <div style={{ display: 'flex', gap: '6px', justifyContent: 'center', marginBottom: '12px' }}>
        {examples.map((e, idx) => (
          <button
            key={idx}
            onClick={() => handleExampleChange(idx)}
            style={{
              padding: '6px 12px',
              background: exampleIdx === idx ? theme.colors.primary : theme.colors.surface,
              border: 'none',
              borderRadius: '6px',
              color: exampleIdx === idx ? '#fff' : theme.colors.textSecondary,
              fontFamily: theme.font,
              fontSize: '11px',
              cursor: 'pointer',
            }}
          >
            {e.name}
          </button>
        ))}
      </div>

      {/* Visualization */}
      <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '12px' }}>
        <canvas
          ref={canvasRef}
          width={size}
          height={size}
          style={{
            borderRadius: '8px',
            border: '1px solid ' + (step === 0 ? theme.colors.primary : theme.colors.border),
            cursor: step === 0 ? 'grab' : 'default',
          }}
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={handleMouseUp}
        />
      </div>

      {/* Centroid Stats */}
      <div style={{
        display: 'flex',
        justifyContent: 'center',
        gap: '8px',
        marginBottom: '12px',
        flexWrap: 'wrap',
      }}>
        {centroids.map((c, i) => (
          <div key={i} style={{
            padding: '6px 10px',
            background: theme.colors.surface,
            borderRadius: '6px',
            border: '2px solid ' + clusterColors[i % clusterColors.length],
          }}>
            <span style={{ fontSize: '9px', color: theme.colors.textMuted }}>C{i + 1}</span>
            <div style={{ fontSize: '12px', fontWeight: '600', color: clusterColors[i % clusterColors.length] }}>
              ({formatNum(c[0])}, {formatNum(c[1])})
            </div>
          </div>
        ))}
        {iteration > 0 && (
          <div style={{
            padding: '6px 10px',
            background: theme.colors.surface,
            borderRadius: '6px',
          }}>
            <span style={{ fontSize: '9px', color: theme.colors.textMuted }}>iter</span>
            <div style={{ fontSize: '12px', fontWeight: '600', color: theme.colors.primary }}>
              {iteration}
            </div>
          </div>
        )}
      </div>

      {/* Step Explanation */}
      <div style={{
        padding: '10px 12px',
        background: theme.colors.surface,
        borderRadius: '8px',
        borderLeft: '3px solid ' + stepInfo[step].color,
        marginBottom: '12px',
      }}>
        <div style={{ fontSize: '12px', fontWeight: '600', color: theme.colors.text }}>
          {stepInfo[step].title}
        </div>
        <div style={{ fontSize: '11px', color: theme.colors.textSecondary, lineHeight: 1.5 }}>
          {stepInfo[step].desc}
        </div>
      </div>

      {/* Step Dots */}
      <div style={{ display: 'flex', gap: '4px', justifyContent: 'center', marginBottom: '12px' }}>
        {Array.from({ length: totalSteps + 1 }).map((_, i) => (
          <div
            key={i}
            style={{
              width: i === step ? '20px' : '8px',
              height: '8px',
              borderRadius: '4px',
              background: i <= step ? theme.colors.primary : theme.colors.border,
              transition: 'all 0.3s',
            }}
          />
        ))}
      </div>

      {/* Controls */}
      <div style={{ display: 'flex', gap: '8px', alignItems: 'center', marginBottom: '12px' }}>
        <button
          onClick={prev}
          disabled={step <= 0 || playing}
          style={{
            padding: '8px 12px',
            background: step <= 0 ? theme.colors.border : theme.colors.surface,
            border: 'none',
            borderRadius: '6px',
            color: step <= 0 ? theme.colors.textMuted : theme.colors.text,
            fontFamily: theme.font,
            fontSize: '14px',
            cursor: step <= 0 ? 'not-allowed' : 'pointer',
          }}
        >
          {'<'}
        </button>
        <button
          onClick={next}
          disabled={step >= totalSteps || playing}
          style={{
            flex: 1,
            padding: '10px 16px',
            background: theme.colors.primary,
            border: 'none',
            borderRadius: '6px',
            color: '#fff',
            fontFamily: theme.font,
            fontSize: '12px',
            fontWeight: '600',
            cursor: step >= totalSteps ? 'not-allowed' : 'pointer',
            opacity: step >= totalSteps ? 0.5 : 1,
          }}
        >
          {step === 0 ? 'Start' : step < totalSteps ? 'Next Step' : 'Complete!'}
        </button>
        <button
          onClick={auto}
          disabled={playing || step >= totalSteps}
          style={{
            padding: '8px 12px',
            background: playing ? theme.colors.border : theme.colors.surface,
            border: 'none',
            borderRadius: '6px',
            color: playing ? theme.colors.textMuted : theme.colors.text,
            fontFamily: theme.font,
            fontSize: '14px',
            cursor: playing ? 'not-allowed' : 'pointer',
          }}
        >
          {playing ? '...' : '>>'}
        </button>
        <button
          onClick={reset}
          style={{
            padding: '8px 12px',
            background: theme.colors.surface,
            border: 'none',
            borderRadius: '6px',
            color: theme.colors.text,
            fontFamily: theme.font,
            fontSize: '14px',
            cursor: 'pointer',
          }}
        >
          {'~'}
        </button>
      </div>

      {/* Math Details */}
      {step >= 1 && (
        <div style={{
          padding: '10px',
          background: theme.colors.surfaceAlt,
          borderRadius: '8px',
          marginBottom: '12px',
        }}>
          {(step === 1 || step === 3) && assignments.length === ex.points.length && (
            <div>
              <div style={{ fontSize: '11px', color: theme.colors.blue, marginBottom: '6px', fontWeight: '600' }}>
                Assignment: each point to nearest centroid
              </div>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
                {centroids.map((_, ci) => {
                  const count = assignments.filter(a => a === ci).length;
                  return (
                    <div key={ci} style={{
                      padding: '4px 8px',
                      background: theme.colors.surface,
                      borderRadius: '4px',
                      fontSize: '10px',
                      border: '1px solid ' + clusterColors[ci % clusterColors.length],
                    }}>
                      <span style={{ color: clusterColors[ci % clusterColors.length] }}>C{ci + 1}: {count} points</span>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {(step === 2 || step === 4) && prevCentroids.length === centroids.length && (
            <div>
              <div style={{ fontSize: '11px', color: theme.colors.green, marginBottom: '6px', fontWeight: '600' }}>
                Update: centroid = mean of cluster points
              </div>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
                {centroids.map((c, ci) => {
                  const prev = prevCentroids[ci] || c;
                  const moved = euclidean(c, prev) > 0.01;
                  return (
                    <div key={ci} style={{
                      padding: '4px 8px',
                      background: theme.colors.surface,
                      borderRadius: '4px',
                      fontSize: '10px',
                      border: '1px solid ' + clusterColors[ci % clusterColors.length],
                    }}>
                      <span style={{ color: clusterColors[ci % clusterColors.length] }}>
                        C{ci + 1}: ({formatNum(prev[0])}, {formatNum(prev[1])}) 
                        {moved ? ' -> ' : ' = '}
                        ({formatNum(c[0])}, {formatNum(c[1])})
                      </span>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {step === 5 && (
            <div>
              <div style={{ fontSize: '11px', color: theme.colors.primary, marginBottom: '6px', fontWeight: '600' }}>
                {converged ? 'Converged!' : 'Running K-Means...'}
              </div>
              <div style={{ fontSize: '10px', color: theme.colors.textSecondary }}>
                {converged 
                  ? 'Centroids stopped moving - clusters are stable'
                  : 'Iterating: assign points, update centroids, repeat...'}
              </div>
              {converged && (
                <div style={{ marginTop: '8px' }}>
                  <div style={{ fontSize: '10px', color: theme.colors.positive }}>
                    Final centroids after {iteration} iterations:
                  </div>
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px', marginTop: '4px' }}>
                    {centroids.map((c, ci) => (
                      <span key={ci} style={{ color: clusterColors[ci % clusterColors.length], fontSize: '10px' }}>
                        C{ci + 1}: ({formatNum(c[0])}, {formatNum(c[1])})
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {/* Key Insight */}
      <div style={{
        padding: '10px 14px',
        background: theme.colors.surface,
        borderRadius: '8px',
        fontSize: '10px',
        color: theme.colors.textSecondary,
        textAlign: 'center',
      }}>
        <strong style={{ color: theme.colors.text }}>Key insight:</strong>{' '}
        K-Means alternates between assigning points and moving centroids until convergence. Initial positions affect final clusters!
      </div>
    </div>
  );
}

